1	// Command mastermind is the ADHD cure for agents that you always
2	// dreamed for yourself.
3	//
4	// It runs as an MCP server over stdio plus CLI subcommands wired to
5	// Claude Code hooks. Together they form a continuity layer: context is
6	// surfaced automatically at session start and after context compaction,
7	// lessons are extracted automatically before compaction, and the user's
8	// working memory is never taxed by the tool itself.
9	//
10	// See the project docs for the design:
11	//   - docs/CONTINUITY.md   — the load-bearing behaviors
12	//   - docs/ARCHITECTURE.md — module layout and MCP tool surface
13	//   - docs/FORMAT.md       — the entry schema (the long-term contract)
14	//   - docs/EXTRACTION.md   — the capture pipeline
15	//   - docs/ARCHIVE.md      — working set vs lifelong archive
16	//   - docs/DECISIONS.md    — the why behind every architectural choice
17	package main
18	
19	import (
20		"context"
21		"encoding/json"
22		"fmt"
23		"os"
24		"os/signal"
25		"path/filepath"
26		"runtime/debug"
27		"sort"
28		"strings"
29		"syscall"
30		"time"
31	
32		"github.com/jeanfbrito/mastermind/internal/discover"
33		"github.com/jeanfbrito/mastermind/internal/extract"
34		"github.com/jeanfbrito/mastermind/internal/format"
35		"github.com/jeanfbrito/mastermind/internal/mcp"
36		"github.com/jeanfbrito/mastermind/internal/project"
37		"github.com/jeanfbrito/mastermind/internal/search"
38		"github.com/jeanfbrito/mastermind/internal/store"
39	)
40	
41	// version is set at build time via -ldflags "-X main.version=..."
42	// Falls back to debug.ReadBuildInfo() for `go install` builds, then to
43	// "dev" as a last resort. Pattern borrowed from engram's main.go.
44	var version = "dev"
45	
46	func init() {
47		if version != "dev" {
48			return
49		}
50		if info, ok := debug.ReadBuildInfo(); ok && info.Main.Version != "" && info.Main.Version != "(devel)" {
51			version = strings.TrimPrefix(info.Main.Version, "v")
52		}
53	}
54	
55	func main() {
56		if len(os.Args) > 1 {
57			switch os.Args[1] {
58			case "version", "--version", "-v":
59				fmt.Printf("mastermind %s\n", version)
60				return
61			case "help", "--help", "-h":
62				printHelp()
63				return
64			case "session-start":
65				if err := runSessionStart(); err != nil {
66					fmt.Fprintf(os.Stderr, "mastermind session-start: %s\n", err)
67					os.Exit(1)
68				}
69				return
70			case "post-compact":
71				if err := runPostCompact(); err != nil {
72					fmt.Fprintf(os.Stderr, "mastermind post-compact: %s\n", err)
73					os.Exit(1)
74				}
75				return
76			case "session-close":
77				// TODO(phase3b): implement in CONTINUITY.md phase 3b.
78				fmt.Fprintln(os.Stderr, "mastermind session-close: not implemented yet — see docs/EXTRACTION.md and docs/ROADMAP.md Phase 3b")
79				os.Exit(1)
80			case "extract":
81				if err := runExtract(); err != nil {
82					fmt.Fprintf(os.Stderr, "mastermind extract: %s\n", err)
83					os.Exit(1)
84				}
85				return
86			case "suggest":
87				if err := runSuggest(); err != nil {
88					fmt.Fprintf(os.Stderr, "mastermind suggest: %s\n", err)
89					os.Exit(1)
90				}
91				return
92			case "discover":
93				if err := runDiscover(); err != nil {
94					fmt.Fprintf(os.Stderr, "mastermind discover: %s\n", err)
95					os.Exit(1)
96				}
97				return
98			case "mcp":
99				// Explicit MCP mode (matches engram's convention: `engram mcp`
100				// to start the stdio server). Fall through to default.
101			default:
102				fmt.Fprintf(os.Stderr, "mastermind: unknown command %q\n\n", os.Args[1])
103				printHelp()
104				os.Exit(2)
105			}
106		}
107	
108		// Default: start the MCP server over stdio. This is the mode
109		// Claude Code spawns mastermind in.
110		if err := runMCPServer(); err != nil {
111			fmt.Fprintf(os.Stderr, "mastermind: %s\n", err)
112			os.Exit(1)
113		}
114	}
115	
116	// buildSessionConfig constructs a store.Config with all three scope
117	// roots populated for the current session:
118	//
119	//   - UserPersonalRoot: ~/.knowledge (from store.DefaultConfig, which resolves
120	//     $HOME).
121	//   - ProjectSharedRoot: <root>/.knowledge when walking upward from cwd finds
122	//     a .knowledge/ directory. Left empty otherwise — the scope disables
123	//     silently rather than creating a new .knowledge/ the user never asked for.
124	//   - ProjectPersonalRoot: ~/.claude/projects/<slug>/memory when cwd is
125	//     inside a git repository. The slug comes from project.DetectFromGit,
126	//     which reads the origin remote first and falls back to the git
127	//     working-tree basename. If cwd is NOT inside a git repo (or
128	//     git is unavailable), the scope is left empty — this is a
129	//     deliberate guard against spawning garbage directories under
130	//     ~/.claude/projects/<random-tmpdir-name>/ every time the binary
131	//     is run from a non-project cwd.
132	//
133	// The chosen naming convention for project-personal — slug, not
134	// dash-encoded cwd — means two clones of the same project on two
135	// machines (e.g., ~/Github/mastermind and ~/code/mastermind) map to
136	// the same directory and the entries merge cleanly on sync. This is
137	// load-bearing for the cross-machine memory story. See the promoted
138	// pattern entry .knowledge/nodes/store-defaultconfig-returns-a-skeleton-...md
139	// and the closed open-loop that originally flagged this design call.
140	//
141	// Escape hatch for the edge case where a slug collision is unwanted
142	// (two unrelated projects that normalize to the same name): a future
143	// MASTERMIND_PROJECT_DIR env var can override this path. Not
144	// implemented yet — add it when a real collision surfaces, not before.
145	func buildSessionConfig(cwd string) (store.Config, error) {
146		cfg, err := store.DefaultConfig()
147		if err != nil {
148			return store.Config{}, err
149		}
150	
151		if root := store.FindProjectRoot(cwd); root != "" {
152			cfg.ProjectSharedRoot = filepath.Join(root, ".knowledge")
153		} else if os.Getenv("MASTERMIND_NO_AUTO_INIT") == "" {
154			// Auto-create .knowledge/ at the git root so project-shared
155			// scope works out of the box. Without this, agents silently
156			// fall back to user-personal and project-specific lessons get
157			// lost. Opt out with MASTERMIND_NO_AUTO_INIT=1.
158			if gitRoot := project.GitRoot(cwd); gitRoot != "" {
159				knowledgeDir := filepath.Join(gitRoot, ".knowledge")
160				if err := os.MkdirAll(knowledgeDir, 0o755); err == nil {
161					cfg.ProjectSharedRoot = knowledgeDir
162					// Seed .gitignore so pending/ (auto-extracted, pre-review)
163					// stays out of version control.
164					gi := filepath.Join(knowledgeDir, ".gitignore")
165					if _, err := os.Stat(gi); os.IsNotExist(err) {
166						_ = os.WriteFile(gi, []byte("pending/\n"), 0o644)
167					}
168				}
169			}
170		}
171	
172		if slug := project.DetectFromGit(cwd); slug != "" {
173			if home, err := os.UserHomeDir(); err == nil {
174				cfg.ProjectPersonalRoot = filepath.Join(home, ".claude", "projects", slug, "memory")
175			}
176		}
177	
178		return cfg, nil
179	}
180	
181	// runMCPServer boots the three-scope store, wires up the searcher and
182	// the MCP server, and runs until the client disconnects or a signal
183	// arrives. Returns any error that escapes the SDK run loop.
184	func runMCPServer() error {
185		cwd, err := os.Getwd()
186		if err != nil {
187			return fmt.Errorf("get cwd: %w", err)
188		}
189		cfg, err := buildSessionConfig(cwd)
190		if err != nil {
191			return fmt.Errorf("build session config: %w", err)
192		}
193	
194		s := store.New(cfg)
195	
196		// Optional auto-promote: when PendingBehavior is "auto-promote",
197		// old pending entries are silently promoted to the live store at
198		// startup. Default (keep-forever) is a no-op. See DECISIONS.md
199		// "Reverse auto-expire" for why entries are never deleted.
200		_, _ = s.AutoPromoteStale()
201	
202		searcher := search.NewKeywordSearcher(s)
203	
204		server, err := mcp.NewServer(mcp.Options{
205			Store:    s,
206			Searcher: searcher,
207			Version:  version,
208		})
209		if err != nil {
210			return fmt.Errorf("build mcp server: %w", err)
211		}
212	
213		// Run the server in a context that's cancelled by SIGINT/SIGTERM
214		// so a clean shutdown happens on Ctrl-C or kill. The SDK's Run
215		// returns when the transport closes, which normally happens when
216		// the parent (Claude Code) exits.
217		ctx, cancel := signal.NotifyContext(context.Background(), os.Interrupt, syscall.SIGTERM)
218		defer cancel()
219	
220		return server.Run(ctx)
221	}
222	
223	// runSessionStart implements the session-start subcommand. It prints
224	// compact markdown to stdout summarizing open loops, project-relevant
225	// entries, and pending counts. The output is injected as system context
226	// by the Claude Code SessionStart hook.
227	//
228	// If there is nothing to surface, it prints nothing and exits 0.
229	// This honors the silent-unless-needed rule from CONTINUITY.md.
230	func runSessionStart() error {
231		cwd := parseCwdFlag()
232		cfg, err := buildSessionConfig(cwd)
233		if err != nil {
234			return fmt.Errorf("build session config: %w", err)
235		}
236	
237		s := store.New(cfg)
238		projectName := project.DetectFromGit(cwd)
239	
240		// Collect open loops from all scopes (live + pending).
241		openLoops, err := collectOpenLoops(s)
242		if err != nil {
243			return fmt.Errorf("collect open loops: %w", err)
244		}
245	
246		// Collect project-relevant entries (non-open-loop).
247		projectEntries, err := collectProjectEntries(s, projectName)
248		if err != nil {
249			return fmt.Errorf("collect project entries: %w", err)
250		}
251	
252		// Count pending entries across all scopes.
253		pendingCount, err := countPending(s)
254		if err != nil {
255			return fmt.Errorf("count pending: %w", err)
256		}
257	
258		output := formatSessionStart(openLoops, projectEntries, pendingCount)
259		if output != "" {
260			fmt.Print(output)
261		}
262		return nil
263	}
264	
265	// parseCwdFlag scans os.Args for --cwd <path> after the subcommand.
266	// Falls back to os.Getwd().
267	func parseCwdFlag() string {
268		for i := 2; i < len(os.Args)-1; i++ {
269			if os.Args[i] == "--cwd" {
270				return os.Args[i+1]
271			}
272		}
273		cwd, err := os.Getwd()
274		if err != nil {
275			return "."
276		}
277		return cwd
278	}
279	
280	// collectOpenLoops gathers all open-loop entries from live and pending
281	// across all three scopes. Open loops are the most critical thing to
282	// surface — they represent in-progress work that would otherwise be
283	// forgotten.
284	func collectOpenLoops(s *store.Store) ([]store.EntryRef, error) {
285		var loops []store.EntryRef
286	
287		for _, scope := range format.AllScopes() {
288			live, err := s.ListLive(scope)
289			if err != nil {
290				return nil, err
291			}
292			for _, ref := range live {
293				if ref.Metadata.Kind == format.KindOpenLoop {
294					loops = append(loops, ref)
295				}
296			}
297	
298			pending, err := s.ListPending(scope)
299			if err != nil {
300				return nil, err
301			}
302			for _, ref := range pending {
303				if ref.Metadata.Kind == format.KindOpenLoop {
304					loops = append(loops, ref)
305				}
306			}
307		}
308	
309		// Sort by date descending (newest first).
310		sortByDateDesc(loops)
311		return loops, nil
312	}
313	
314	// collectProjectEntries gathers non-open-loop entries relevant to the
315	// current project. From project-shared and project-personal scopes it
316	// takes everything; from user-personal it filters by project name.
317	// Returns at most 5 entries, sorted by date descending.
318	func collectProjectEntries(s *store.Store, projectName string) ([]store.EntryRef, error) {
319		var entries []store.EntryRef
320	
321		// Project-shared and project-personal: all entries are project-relevant by definition.
322		for _, scope := range []format.Scope{format.ScopeProjectShared, format.ScopeProjectPersonal} {
323			live, err := s.ListLive(scope)
324			if err != nil {
325				return nil, err
326			}
327			for _, ref := range live {
328				if ref.Metadata.Kind != format.KindOpenLoop {
329					entries = append(entries, ref)
330				}
331			}
332		}
333	
334		// User-personal: only entries matching the current project.
335		if projectName != "" {
336			live, err := s.ListLive(format.ScopeUserPersonal)
337			if err != nil {
338				return nil, err
339			}
340			for _, ref := range live {
341				if ref.Metadata.Kind != format.KindOpenLoop &&
342					strings.EqualFold(ref.Metadata.Project, projectName) {
343					entries = append(entries, ref)
344				}
345			}
346		}
347	
348		sortByDateDesc(entries)
349	
350		// Cap at 5.
351		if len(entries) > 5 {
352			entries = entries[:5]
353		}
354		return entries, nil
355	}
356	
357	// countPending returns the total number of pending entries across all scopes.
358	func countPending(s *store.Store) (int, error) {
359		var count int
360		for _, scope := range format.AllScopes() {
361			refs, err := s.ListPending(scope)
362			if err != nil {
363				return 0, err
364			}
365			count += len(refs)
366		}
367		return count, nil
368	}
369	
370	// formatSessionStart renders the session-start output as compact markdown.
371	// Returns empty string when there's nothing to surface.
372	func formatSessionStart(openLoops, projectEntries []store.EntryRef, pendingCount int) string {
373		if len(openLoops) == 0 && len(projectEntries) == 0 && pendingCount == 0 {
374			return ""
375		}
376	
377		var b strings.Builder
378		b.WriteString("## mastermind\n\n")
379	
380		if len(openLoops) > 0 {
381			fmt.Fprintf(&b, "**Open loops** (%d):\n", len(openLoops))
382			for _, ref := range openLoops {
383				fmt.Fprintf(&b, "- %s (%s)\n", ref.Metadata.Topic, ref.Metadata.Date)
384			}
385			b.WriteByte('\n')
386		}
387	
388		if len(projectEntries) > 0 {
389			fmt.Fprintf(&b, "**Project knowledge** (%d entries):\n", len(projectEntries))
390			for _, ref := range projectEntries {
391				fmt.Fprintf(&b, "- %s · %s\n", ref.Metadata.Topic, ref.Metadata.Kind)
392			}
393			b.WriteByte('\n')
394		}
395	
396		if pendingCount > 0 {
397			fmt.Fprintf(&b, "**Pending review**: %d entries awaiting review.\n\n", pendingCount)
398		}
399	
400		b.WriteString("_Use mm_search before complex tasks. Call mm_write to capture lessons as you work._\n")
401		return b.String()
402	}
403	
404	// ─── post-compact subcommand ──────────────────────────────────────────
405	
406	// runPostCompact implements the post-compact subcommand. It fires after
407	// Claude Code compresses the conversation context, at which point the
408	// agent has lost most of its working memory. Re-injecting the curated
409	// project slice re-hydrates project context so the next turn starts
410	// oriented rather than blank.
411	//
412	// Scope is narrower than session-start: project-shared and
413	// project-personal only. User-personal and cross-project open loops
414	// are omitted — PostCompact is specifically about re-hydrating the
415	// project the agent was just working in, not the full session picture.
416	//
417	// PostCompact hook input JSON may include session_id and cwd fields.
418	// We read them if present but fall back to cwd flag / os.Getwd().
419	// Silent on stdin errors (hook may not provide input in all versions).
420	//
421	// If there is nothing to surface, prints nothing and exits 0.
422	// This honors the silent-unless-needed rule from CONTINUITY.md.
423	func runPostCompact() error {
424		// PostCompact hook sends JSON on stdin (same shape as hookInput).
425		// Try to decode it, but don't fail if stdin is empty or malformed.
426		cwd := parseCwdFlag()
427		var input hookInput
428		if err := json.NewDecoder(os.Stdin).Decode(&input); err == nil {
429			if input.Cwd != "" {
430				cwd = input.Cwd
431			}
432		}
433	
434		cfg, err := buildSessionConfig(cwd)
435		if err != nil {
436			return fmt.Errorf("build session config: %w", err)
437		}
438	
439		s := store.New(cfg)
440		projectName := project.DetectFromGit(cwd)
441	
442		// Collect project-scoped open loops only (not user-personal).
443		openLoops, err := collectProjectOpenLoops(s)
444		if err != nil {
445			return fmt.Errorf("collect project open loops: %w", err)
446		}
447	
448		// Collect project-relevant knowledge entries.
449		projectEntries, err := collectProjectEntries(s, projectName)
450		if err != nil {
451			return fmt.Errorf("collect project entries: %w", err)
452		}
453	
454		output := formatPostCompact(openLoops, projectEntries)
455		if output != "" {
456			fmt.Print(output)
457		}
458		return nil
459	}
460	
461	// collectProjectOpenLoops gathers open-loop entries from project-scoped
462	// stores only (project-shared and project-personal). User-personal open
463	// loops are excluded — PostCompact is about re-hydrating the current
464	// project, not the full user knowledge picture.
465	func collectProjectOpenLoops(s *store.Store) ([]store.EntryRef, error) {
466		var loops []store.EntryRef
467	
468		for _, scope := range []format.Scope{format.ScopeProjectShared, format.ScopeProjectPersonal} {
469			live, err := s.ListLive(scope)
470			if err != nil {
471				return nil, err
472			}
473			for _, ref := range live {
474				if ref.Metadata.Kind == format.KindOpenLoop {
475					loops = append(loops, ref)
476				}
477			}
478	
479			pending, err := s.ListPending(scope)
480			if err != nil {
481				return nil, err
482			}
483			for _, ref := range pending {
484				if ref.Metadata.Kind == format.KindOpenLoop {
485					loops = append(loops, ref)
486				}
487			}
488		}
489	
490		sortByDateDesc(loops)
491		return loops, nil
492	}
493	
494	// formatPostCompact renders the post-compact injection as compact markdown.
495	// Returns empty string when there's nothing to surface.
496	// Omits pending count (noise after compaction) and keeps the header terse.
497	func formatPostCompact(openLoops, projectEntries []store.EntryRef) string {
498		if len(openLoops) == 0 && len(projectEntries) == 0 {
499			return ""
500		}
501	
502		var b strings.Builder
503		b.WriteString("## mastermind (post-compact)\n\n")
504	
505		if len(openLoops) > 0 {
506			fmt.Fprintf(&b, "**Open loops** (%d):\n", len(openLoops))
507			for _, ref := range openLoops {
508				fmt.Fprintf(&b, "- %s (%s)\n", ref.Metadata.Topic, ref.Metadata.Date)
509			}
510			b.WriteByte('\n')
511		}
512	
513		if len(projectEntries) > 0 {
514			fmt.Fprintf(&b, "**Project knowledge** (%d entries):\n", len(projectEntries))
515			for _, ref := range projectEntries {
516				fmt.Fprintf(&b, "- %s · %s\n", ref.Metadata.Topic, ref.Metadata.Kind)
517			}
518			b.WriteByte('\n')
519		}
520	
521		b.WriteString("_Context was just compacted. Use mm_search if you need deeper context._\n")
522		return b.String()
523	}
524	
525	// ─── extract subcommand ────────────────────────────────────────────────
526	
527	// hookInput is the JSON structure Claude Code sends to hooks on stdin.
528	type hookInput struct {
529		TranscriptPath string `json:"transcript_path"`
530		SessionID      string `json:"session_id"`
531		Cwd            string `json:"cwd"`
532	}
533	
534	// runExtract implements the extract subcommand. It reads the conversation
535	// transcript (either from a hook's stdin JSON or from a --transcript flag)
536	// and extracts knowledge entries into pending/.
537	//
538	// Extraction mode is controlled by env vars:
539	//   - MASTERMIND_EXTRACT_MODE: "keyword" (default) or "llm"
540	//   - MASTERMIND_LLM_PROVIDER: "anthropic" (default) or "ollama"
541	//   - MASTERMIND_LLM_MODEL: model identifier
542	func runExtract() error {
543		var transcriptPath, cwd string
544	
545		// Check for --from-hook flag: read JSON from stdin.
546		fromHook := false
547		for _, arg := range os.Args[2:] {
548			if arg == "--from-hook" {
549				fromHook = true
550			}
551		}
552	
553		if fromHook {
554			var input hookInput
555			if err := json.NewDecoder(os.Stdin).Decode(&input); err != nil {
556				return fmt.Errorf("decode hook input: %w", err)
557			}
558			transcriptPath = input.TranscriptPath
559			cwd = input.Cwd
560		} else {
561			// Manual mode: --transcript <path>
562			for i := 2; i < len(os.Args)-1; i++ {
563				switch os.Args[i] {
564				case "--transcript":
565					transcriptPath = os.Args[i+1]
566				case "--cwd":
567					cwd = os.Args[i+1]
568				}
569			}
570		}
571	
572		if transcriptPath == "" {
573			return fmt.Errorf("no transcript path provided (use --from-hook or --transcript <path>)")
574		}
575	
576		if cwd == "" {
577			var err error
578			cwd, err = os.Getwd()
579			if err != nil {
580				cwd = "."
581			}
582		}
583	
584		// Read the transcript.
585		data, err := os.ReadFile(transcriptPath)
586		if err != nil {
587			return fmt.Errorf("read transcript: %w", err)
588		}
589		transcript := string(data)
590		if strings.TrimSpace(transcript) == "" {
591			return nil // nothing to extract
592		}
593	
594		// Build store config for the cwd context.
595		cfg, err := buildSessionConfig(cwd)
596		if err != nil {
597			return fmt.Errorf("build session config: %w", err)
598		}
599		s := store.New(cfg)
600	
601		// Collect existing topics for deduplication.
602		existingTopics := collectExistingTopics(s)
603	
604		// Configure the extractor.
605		projectName := project.DetectFromGit(cwd)
606		if projectName == "" {
607			projectName = project.Detect(cwd)
608		}
609	
610		extractCfg := extract.Config{
611			Mode:        envOrDefault("MASTERMIND_EXTRACT_MODE", "keyword"),
612			LLMProvider: envOrDefault("MASTERMIND_LLM_PROVIDER", "anthropic"),
613			LLMModel:    os.Getenv("MASTERMIND_LLM_MODEL"),
614			OllamaURL:   envOrDefault("MASTERMIND_OLLAMA_URL", "http://localhost:11434"),
615			ProjectName: projectName,
616		}
617		extractor := extract.NewExtractor(extractCfg)
618	
619		// Extract entries.
620		entries, err := extractor.Extract(transcript, existingTopics)
621		if err != nil {
622			return fmt.Errorf("extract: %w", err)
623		}
624	
625		if len(entries) == 0 {
626			fmt.Fprintf(os.Stderr, "mastermind extract: no entries extracted\n")
627			return nil
628		}
629	
630		// Write each entry to pending/.
631		var written int
632		for i := range entries {
633			// Assign scope: project-shared if project store is configured,
634			// otherwise user-personal.
635			if cfg.ProjectSharedRoot != "" {
636				entries[i].Metadata.Scope = format.ScopeProjectShared
637			} else {
638				entries[i].Metadata.Scope = format.ScopeUserPersonal
639			}
640	
641			if _, err := s.Write(&entries[i]); err != nil {
642				fmt.Fprintf(os.Stderr, "mastermind extract: write failed for %q: %v\n", entries[i].Metadata.Topic, err)
643				continue
644			}
645			written++
646		}
647	
648		fmt.Fprintf(os.Stderr, "mastermind extract: %d entries written to pending/\n", written)
649		return nil
650	}
651	
652	// collectExistingTopics gathers all topic strings from the live store
653	// across all scopes. Used for deduplication during extraction.
654	func collectExistingTopics(s *store.Store) []string {
655		var topics []string
656		for _, scope := range format.AllScopes() {
657			refs, err := s.ListLive(scope)
658			if err != nil {
659				continue
660			}
661			for _, ref := range refs {
662				topics = append(topics, ref.Metadata.Topic)
663			}
664		}
665		return topics
666	}
667	
668	// envOrDefault returns the environment variable value or a default.
669	func envOrDefault(key, defaultVal string) string {
670		if v := os.Getenv(key); v != "" {
671			return v
672		}
673		return defaultVal
674	}
675	
676	// ─── discover subcommand ──────────────────────────────────────────────
677	
678	// runDiscover implements the discover subcommand. It mines git history
679	// and/or source code for knowledge using an LLM (Haiku or any
680	// OpenAI-compatible endpoint) and writes entries to pending/.
681	func runDiscover() error {
682		mode := "all"
683		depth := 100
684		cwd, _ := os.Getwd()
685	
686		// Simple flag parsing (no flag package — matches other subcommands).
687		args := os.Args[2:]
688		for i := 0; i < len(args); i++ {
689			switch args[i] {
690			case "--mode":
691				if i+1 < len(args) {
692					mode = args[i+1]
693					i++
694				}
695			case "--depth":
696				if i+1 < len(args) {
697					fmt.Sscanf(args[i+1], "%d", &depth)
698					i++
699				}
700			case "--cwd":
701				if i+1 < len(args) {
702					cwd = args[i+1]
703					i++
704				}
705			default:
706				// Positional: treat as mode if it's a known value.
707				if args[i] == "git" || args[i] == "codebase" || args[i] == "all" {
708					mode = args[i]
709				}
710			}
711		}
712	
713		cfg, err := buildSessionConfig(cwd)
714		if err != nil {
715			return err
716		}
717		s := store.New(cfg)
718	
719		projectName := project.DetectFromGit(cwd)
720		if projectName == "" {
721			projectName = "general"
722		}
723	
724		provider := envOrDefault("MASTERMIND_LLM_PROVIDER", "anthropic")
725		apiKey := os.Getenv("ANTHROPIC_API_KEY")
726		if provider == "openai" {
727			apiKey = os.Getenv("MASTERMIND_LLM_API_KEY")
728		}
729	
730		disc, err := discover.New(discover.Config{
731			Mode:        mode,
732			Depth:       depth,
733			Cwd:         cwd,
734			ProjectName: projectName,
735			LLMProvider: provider,
736			LLMModel:    os.Getenv("MASTERMIND_LLM_MODEL"),
737			BaseURL:     os.Getenv("MASTERMIND_LLM_BASE_URL"),
738			APIKey:      apiKey,
739		}, s)
740		if err != nil {
741			return err
742		}
743	
744		fmt.Fprintf(os.Stderr, "mastermind discover: mode=%s depth=%d provider=%s\n", mode, depth, provider)
745	
746		result, err := disc.Run()
747		if err != nil {
748			return err
749		}
750	
751		fmt.Fprintf(os.Stderr, "\nDiscovery complete: %d entries written to pending/\n", len(result.Entries))
752		if result.CommitsAnalyzed > 0 || result.CommitsSkipped > 0 {
753			fmt.Fprintf(os.Stderr, "  Git: %d commits analyzed, %d skipped (already discovered)\n", result.CommitsAnalyzed, result.CommitsSkipped)
754		}
755		if result.PackagesScanned > 0 {
756			fmt.Fprintf(os.Stderr, "  Codebase: %d packages scanned\n", result.PackagesScanned)
757		}
758		if len(result.Entries) > 0 {
759			fmt.Fprintf(os.Stderr, "\nRun /mm-review to promote the good ones.\n")
760		}
761	
762		return nil
763	}
764	
765	// ─── suggest subcommand ────────────────────────────────────────────────
766	
767	// suggestHookInput is the JSON structure Claude Code sends to PostToolUse hooks.
768	type suggestHookInput struct {
769		ToolName  string          `json:"tool_name"`
770		ToolInput json.RawMessage `json:"tool_input"`
771		Cwd       string          `json:"cwd"`
772		SessionID string          `json:"session_id"`
773	}
774	
775	// suggestToolInput extracts file_path from the tool_input JSON.
776	type suggestToolInput struct {
777		FilePath string `json:"file_path"`
778	}
779	
780	// skipSegments are directory names too generic to match against topic dirs.
781	var skipSegments = map[string]bool{
782		"internal": true, "src": true, "lib": true, "pkg": true,
783		"cmd": true, "app": true, "test": true, "tests": true,
784		"spec": true, "specs": true, "build": true, "dist": true,
785		"node_modules": true, "vendor": true, "components": true,
786		"utils": true, "helpers": true, "common": true, "shared": true,
787		"main": true, "index": true, "types": true, "models": true,
788	}
789	
790	// runSuggest implements the suggest subcommand. It reads PostToolUse
791	// hook input from stdin, checks if mastermind has knowledge about the
792	// file being touched, and outputs a one-line nudge if so.
793	//
794	// Design: directory stat, not search. Checks if topic directories
795	// matching the file path exist in any .knowledge/ scope. If yes,
796	// counts entries and outputs a nudge. If no, outputs nothing.
797	// Executes in <10ms.
798	func runSuggest() error {
799		var input suggestHookInput
800		if err := json.NewDecoder(os.Stdin).Decode(&input); err != nil {
801			return nil // silent on bad input — don't block the agent
802		}
803	
804		var toolInput suggestToolInput
805		if err := json.Unmarshal(input.ToolInput, &toolInput); err != nil || toolInput.FilePath == "" {
806			return nil // no file path — nothing to suggest
807		}
808	
809		// Extract keywords from the file path.
810		keywords := extractPathKeywords(toolInput.FilePath)
811		if len(keywords) == 0 {
812			return nil
813		}
814	
815		// Build store config to find scope roots.
816		cwd := input.Cwd
817		if cwd == "" {
818			cwd, _ = os.Getwd()
819		}
820		cfg, err := buildSessionConfig(cwd)
821		if err != nil {
822			return nil
823		}
824	
825		// Check each keyword against topic dirs in all scope roots.
826		roots := []string{cfg.UserPersonalRoot, cfg.ProjectSharedRoot, cfg.ProjectPersonalRoot}
827	
828		type topicMatch struct {
829			dir      string // directory keyword that matched
830			count    int
831			topTopic string // topic from the best entry (most recent)
832		}
833		var matches []topicMatch
834		seen := make(map[string]bool)
835	
836		for _, kw := range keywords {
837			if seen[kw] {
838				continue
839			}
840			seen[kw] = true
841	
842			total := 0
843			var bestTopic string
844			for _, root := range roots {
845				if root == "" {
846					continue
847				}
848				dir := filepath.Join(root, kw)
849				total += countEntriesInDir(dir)
850				if bestTopic == "" {
851					bestTopic = bestEntryTopic(dir)
852				}
853			}
854			if total > 0 {
855				matches = append(matches, topicMatch{dir: kw, count: total, topTopic: bestTopic})
856			}
857		}
858	
859		if len(matches) == 0 {
860			return nil
861		}
862	
863		// Debounce: skip if we suggested the same file recently.
864		debounceFile := filepath.Join(os.TempDir(), "mastermind-suggest-debounce")
865		debounceKey := toolInput.FilePath
866		if data, err := os.ReadFile(debounceFile); err == nil {
867			parts := strings.SplitN(string(data), "|", 2)
868			if len(parts) == 2 && parts[1] == debounceKey {
869				if ts, err := time.Parse(time.RFC3339, parts[0]); err == nil {
870					if time.Since(ts) < 60*time.Second {
871						return nil // debounced
872					}
873				}
874			}
875		}
876		_ = os.WriteFile(debounceFile, []byte(time.Now().Format(time.RFC3339)+"|"+debounceKey), 0o644)
877	
878		// Format nudge with the top entry's topic for immediate context.
879		best := matches[0]
880		if best.topTopic != "" {
881			extra := best.count - 1
882			if extra > 0 {
883				fmt.Printf("_mastermind: \"%s\" + %d more in %q — consider mm_search._\n", best.topTopic, extra, best.dir)
884			} else {
885				fmt.Printf("_mastermind: \"%s\" — consider mm_search._\n", best.topTopic)
886			}
887		} else {
888			fmt.Printf("_mastermind has knowledge about %q (%d entries) — consider mm_search._\n", best.dir, best.count)
889		}
890		return nil
891	}
892	
893	// extractPathKeywords pulls meaningful keywords from a file path.
894	// Skips generic directory names and returns lowercase segments.
895	func extractPathKeywords(filePath string) []string {
896		// Take the last 4 segments of the path (dirs + filename).
897		parts := strings.Split(filepath.Clean(filePath), string(filepath.Separator))
898		if len(parts) > 4 {
899			parts = parts[len(parts)-4:]
900		}
901	
902		var keywords []string
903		for _, p := range parts {
904			// Strip file extension for the filename.
905			if ext := filepath.Ext(p); ext != "" {
906				p = strings.TrimSuffix(p, ext)
907			}
908			p = strings.ToLower(p)
909			if p == "" || skipSegments[p] || len(p) < 2 {
910				continue
911			}
912			keywords = append(keywords, p)
913		}
914		return keywords
915	}
916	
917	// countEntriesInDir counts .md files in a directory and its subdirs.
918	// Returns 0 if the directory doesn't exist.
919	func countEntriesInDir(dir string) int {
920		info, err := os.Stat(dir)
921		if err != nil || !info.IsDir() {
922			return 0
923		}
924		count := 0
925		filepath.WalkDir(dir, func(path string, d os.DirEntry, err error) error {
926			if err != nil {
927				return nil
928			}
929			if !d.IsDir() && strings.HasSuffix(d.Name(), ".md") {
930				count++
931			}
932			return nil
933		})
934		return count
935	}
936	
937	// bestEntryTopic reads the most recently modified .md file in dir and
938	// returns its topic from frontmatter. Returns "" if the dir doesn't
939	// exist, has no entries, or parsing fails. Designed to add <1ms to the
940	// suggest path — reads one small file.
941	func bestEntryTopic(dir string) string {
942		info, err := os.Stat(dir)
943		if err != nil || !info.IsDir() {
944			return ""
945		}
946	
947		var bestPath string
948		var bestTime time.Time
949		filepath.WalkDir(dir, func(path string, d os.DirEntry, err error) error {
950			if err != nil || d.IsDir() || !strings.HasSuffix(d.Name(), ".md") {
951				return nil
952			}
953			if fi, err := d.Info(); err == nil {
954				if bestPath == "" || fi.ModTime().After(bestTime) {
955					bestPath = path
956					bestTime = fi.ModTime()
957				}
958			}
959			return nil
960		})
961	
962		if bestPath == "" {
963			return ""
964		}
965		data, err := os.ReadFile(bestPath)
966		if err != nil {
967			return ""
968		}
969		entry, err := format.Parse(data)
970		if err != nil {
971			return ""
972		}
973		return entry.Metadata.Topic
974	}
975	
976	// sortByDateDesc sorts entry refs by date descending (newest first).
977	// Entries with identical dates are sorted by path for determinism.
978	func sortByDateDesc(refs []store.EntryRef) {
979		sort.Slice(refs, func(i, j int) bool {
980			if refs[i].Metadata.Date != refs[j].Metadata.Date {
981				return refs[i].Metadata.Date > refs[j].Metadata.Date
982			}
983			return refs[i].Path < refs[j].Path
984		})
985	}
986	
987	func printHelp() {
988		fmt.Fprintf(os.Stderr, `mastermind %s — the ADHD cure for agents that you always dreamed for yourself
989	
990	Usage:
991	  mastermind                    Start MCP server over stdio (default; used by Claude Code)
992	  mastermind mcp                Explicit: start MCP server
993	  mastermind session-start      Claude Code session-start hook (surfaces open loops + project context)
994	  mastermind post-compact       Claude Code PostCompact hook (re-injects project context after compaction)
995	  mastermind session-close      Claude Code session-close hook (phase 3b, not implemented)
996	  mastermind extract            Extract knowledge from a conversation transcript
997	  mastermind suggest            PostToolUse hook — nudge when knowledge exists for a file
998	  mastermind discover           Mine git history + codebase for knowledge (Haiku / OpenAI-compat)
999	  mastermind version            Print version and exit
1000	  mastermind help               Show this help
1001	
1002	Discover options:
1003	  mastermind discover [git|codebase|all] [--depth N] [--cwd DIR]
1004	
1005	  Env vars: MASTERMIND_LLM_PROVIDER (anthropic|openai)
1006	            MASTERMIND_LLM_MODEL, MASTERMIND_LLM_BASE_URL, MASTERMIND_LLM_API_KEY
1007	            ANTHROPIC_API_KEY (for anthropic provider)
1008	
1009	MCP tools (for agent use):
1010	  mm_search       Search persistent knowledge across scopes
1011	  mm_write        Write a candidate entry to the pending-review queue
1012	  mm_promote      Move a pending entry to the live store (user-gated)
1013	  mm_close_loop   Mark an open-loop as resolved (phase 3, not implemented)
1014	
1015	Setup:
1016	  mastermind expects a ~/.knowledge/ directory. Initialize it as a git repo
1017	  with a remote for cross-machine sync. Then add mastermind to your
1018	  Claude Code MCP config:
1019	
1020	    {
1021	      "mcpServers": {
1022	        "mastermind": {
1023	          "type": "stdio",
1024	          "command": "mastermind"
1025	        }
1026	      }
1027	    }
1028	
1029	Docs: see the project docs/ directory for the full design.
1030	`, version)
1031	}
1032

