import json, re

path = '/Users/jean/.claude/projects/-Users-jean-Github-mastermind/01cda02f-6bee-4821-a25f-913d6f7f9ccf.jsonl'

# Reconstruct the prose the extractor would see (mirror NormalizeTranscript logic).
prose_parts = []
with open(path) as f:
    for line in f:
        line = line.strip()
        if not line:
            continue
        try:
            env = json.loads(line)
        except:
            continue
        if env.get('type') not in ('user', 'assistant'):
            continue
        msg = env.get('message', {})
        content = msg.get('content')
        if isinstance(content, str):
            text = content
        elif isinstance(content, list):
            parts = [b.get('text', '') for b in content if b.get('type') == 'text']
            text = '\n'.join(p for p in parts if p)
        else:
            text = ''
        if text.strip():
            role = 'User' if env['type'] == 'user' else 'Assistant'
            prose_parts.append(f"{role}: {text}")

prose = '\n\n'.join(prose_parts)
print(f"prose size: {len(prose)} chars, {len(prose_parts)} turns")

# Signal phrases from keyword.go (simplified)
signals = {
    'lesson': [r'the fix was', r'solved by', r'root cause', r'the real issue', r'turned out to be', r'lesson learned', r'next time', r'remember to'],
    'war-story': [r'wasted hours', r'hours debugging', r'painful', r'nightmare', r'kept failing'],
    'decision': [r"decided to", r"decision:", r"we chose", r"chose .* over", r"went with", r"i'll use", r"i'll go with", r"let's use", r"the plan is", r"going to"],
    'pattern': [r'the pattern is', r'always do', r'never do', r'best practice', r'the right way to'],
    'open-loop': [r'TODO:', r'we should', r'come back to', r'still need to', r"haven't .* yet"],
    'insight': [r'realized that', r'discovered that', r'turns out', r'surprisingly', r'non-obvious', r'found that', r'the issue was'],
}

found = []
for kind, pats in signals.items():
    for pat in pats:
        for m in re.finditer(pat, prose, re.IGNORECASE):
            start = max(0, m.start() - 30)
            end = min(len(prose), m.end() + 80)
            snippet = prose[start:end].replace('\n', ' ')
            found.append((kind, pat, snippet))

print(f"\nsignal hits: {len(found)}\n")
# Print first 30 hits
for kind, pat, snippet in found[:30]:
    print(f"  [{kind:9}] {pat!r:25} → ...{snippet[:120]}...")

